INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("キャル", "たまには\n協力するのもいいんじゃない？\nあたしも手を貸してあげる", "2030/12/17 14:59:59", 1, 106001, -363.0, 7001, "2015/12/17 15:00:00", 7, 0.0, 0, 0.0, 0, 1, 1);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("コッコロ", "多くの方と協力して\n戦えるようです\n主さまなら、さぞ\nご活躍なさることでしょう", "2030/12/17 14:59:59", 1, 105901, -363.0, 7002, "2015/12/17 15:00:00", 7, 0.0, 0, 0.0, 0, 1, 1);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("ペコリーヌ", "たくさんの人と一緒に\n協力バトルです！\nがんばりましょう☆", "2030/12/17 14:59:59", 1, 105801, -363.0, 7003, "2015/12/17 15:00:00", 7, 0.0, 0, 0.0, 0, 1, 1);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("ペコリーヌ", "ジュエルを食べ物…\nいえ、貴重品と交換できます！", "2030/12/17 14:59:59", 1, 105801, -363.0, 10001, "2015/12/17 15:00:00", 10, 0.0, 0, 0.0, 0, 1, 1);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("キャル", "ジュエルはよく考えて\n使うことね\n無駄遣い厳禁！", "2030/12/17 14:59:59", 1, 106001, -363.0, 10002, "2015/12/17 15:00:00", 10, 0.0, 0, 0.0, 0, 1, 1);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("コッコロ", "主さまのジュエルで\n貴重な品々を購入できます\nですが、無駄遣いは\n『めっ』でございますよ", "2030/12/17 14:59:59", 1, 105901, -363.0, 10003, "2015/12/17 15:00:00", 10, 0.0, 0, 0.0, 0, 1, 1);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("シェフィ", "ジュエルがあれば\n貴重品と交換できるみたい\n大事に使いましょうね", "2030/12/17 14:59:59", 2, 106401, -363.0, 10004, "2015/12/17 15:00:00", 10, 0.0, 2104010, 0.0, 0, 1, 1);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("ペコリーヌ", "特定の条件を達成すると\n報酬がもらえますよ！\nがんばりましょう♪　", "2030/12/17 14:59:59", 1, 105801, -416.5, 12001, "2015/12/17 15:00:00", 12, 0.0, 0, 0.0, 0, 1, 1);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("キャル", "思い出が詰まってるって\nいろいろあったけど\n振り返るのもいいんじゃない？", "2030/12/17 14:59:59", 1, 106001, -363.0, 13001, "2015/12/17 15:00:00", 13, 0.0, 0, 0.0, 0, 1, 1);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("コッコロ", "主さまとの楽しい日々…\nこちらで何度でも\n思い返しましょう♪", "2030/12/17 14:59:59", 1, 105901, -363.0, 13002, "2015/12/17 15:00:00", 13, 0.0, 0, 0.0, 0, 1, 1);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("シェフィ", "みんなとの大切な思い出が\nたくさん詰まってるのね\n一緒に振り返って、\n心に刻みたいわ", "2030/12/17 14:59:59", 2, 106401, -363.0, 13003, "2015/12/17 15:00:00", 13, 0.0, 2104010, 0.0, 0, 1, 1);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("ペコリーヌ", "女の子との思い出が\nたくさん見られますよ！\nヒューヒュー♪\nモテモテですねー☆", "2030/12/17 14:59:59", 1, 105801, -363.0, 13004, "2015/12/17 15:00:00", 13, 0.0, 0, 0.0, 0, 1, 1);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("コッコロ", "育成に必要なアイテムが\n獲得できるクエストです\nわたくし、主さまのために、\n強くなりますよ", "2030/12/17 14:59:59", 1, 105901, -363.0, 14001, "2015/12/17 15:00:00", 14, 0.0, 0, 0.0, 0, 1, 1);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("シェフィ", "このクエストを攻略すると、\nアイテムが手に入るらしいわ。\nもっと強くなるために、\n一生懸命がんばるわね！", "2030/12/17 14:59:59", 2, 106401, -363.0, 14002, "2015/12/17 15:00:00", 14, 0.0, 2104010, 0.0, 0, 1, 1);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("ペコリーヌ", "このクエストを攻略すれば、\nアイテムがもらえますよ\nたくさん集めて、どんどん\n強くなっちゃいましょう！", "2030/12/17 14:59:59", 1, 105801, -363.0, 14003, "2015/12/17 15:00:00", 14, 0.0, 0, 0.0, 0, 1, 1);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("キャル", "クエストを攻略すると、\nアイテムが手に入るんだって\nもらえるものは、\nもらっておきましょ！", "2030/12/17 14:59:59", 1, 106001, -363.0, 14004, "2015/12/17 15:00:00", 14, 0.0, 0, 0.0, 0, 1, 1);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("コッコロ", "主さま、旅の準備を整えて\nより充実した冒険をいたし\nましょう", "2030/12/17 14:59:59", 1, 105901, -470.0, 15001, "2015/12/17 15:00:00", 15, 0.0, 0, 0.0, 0, 1, 1);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("シェフィ", "ねぇ…クランに加入してみない？\n一人も楽しいけど、みんなと\n一緒も賑やかでいいと思うの", "2030/12/17 14:59:59", 2, 106401, -363.0, 16001, "2015/12/17 15:00:00", 16, 0.0, 2104010, 0.0, 0, 1, 1);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("ペコリーヌ", "クランに加入してみませんか？\nみんなといっしょに冒険した方が、\n楽しいですよ！", "2030/12/17 14:59:59", 1, 105801, -363.0, 16002, "2015/12/17 15:00:00", 16, 0.0, 0, 0.0, 0, 1, 1);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("キャル", "クランに入れるらしいわよ\nせっかくだから入ってみたら？\nけっこう楽しいみたいよ♪", "2030/12/17 14:59:59", 1, 106001, -363.0, 16003, "2015/12/17 15:00:00", 16, 0.0, 0, 0.0, 0, 1, 1);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("コッコロ", "こちらでクランに加入できます\n素敵なクランがたくさんあって、\n目移りしてしまいますね", "2030/12/17 14:59:59", 1, 105901, -363.0, 16004, "2015/12/17 15:00:00", 16, 0.0, 0, 0.0, 0, 1, 1);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("コッコロ", " こちらではクランバトルに\n 参加された仲間のみなさんの\n 活躍を振り返ることができます", "2030/12/17 14:59:59", 1, 105901, -363.0, 17002, "2015/12/17 15:00:00", 17, 0.0, 0, 0.0, 0, 1, 1);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("キャル", "模擬戦の戦績もアンタが\n気に入ったものがあれば\n記録しておけるのね", "2030/12/17 14:59:59", 1, 106001, -363.0, 17004, "2015/12/17 15:00:00", 25, 0.0, 0, 0.0, 0, 1, 1);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("コッコロ", "主さま、今回のクランバトルでの\nご活躍が記録されています\nバトルの参考にいたしましょう", "2030/12/17 14:59:59", 1, 105901, -363.0, 17005, "2015/12/17 15:00:00", 25, 0.0, 0, 0.0, 0, 1, 1);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("シェフィ", "今回のクランバトルの調子は\nどうかしら？\n戦績を見れば、次のバトルに\n活かせるかもしれないわ", "2030/12/17 14:59:59", 2, 106401, -363.0, 17006, "2015/12/17 15:00:00", 25, 0.0, 2104010, 0.0, 0, 1, 1);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("ペコリーヌ", "今回のクランバトルでの戦績を\nおさらいできますよ！\n私にも見せてください☆", "2030/12/17 14:59:59", 1, 105801, -363.0, 17007, "2015/12/17 15:00:00", 25, 0.0, 0, 0.0, 0, 1, 1);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("カリン", "ようこそ！\nこちらでは、\nギルドハウスで流れる音楽の\n変更や購入が出来ますよ", "2030/12/17 14:59:59", 1, 190801, -363.0, 18001, "2015/12/17 15:00:00", 18, 0.0, 0, 0.0, 0, 1, 1);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("カリン", "ＢＧＭの変更や購入は、こちらから\nできますよ\n素敵な音楽を、たくさんご用意\nいたしました！", "2030/12/17 14:59:59", 1, 190801, -363.0, 18002, "2015/12/17 15:00:00", 18, 0.0, 0, 0.0, 0, 2, 1);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("カリン", "ギルドハウスの\nＢＧＭを変更できますよ\nあなたの好きな曲、\n私にも聴かせてくださいね", "2030/12/17 14:59:59", 1, 190801, -470.0, 19001, "2015/12/17 15:00:00", 19, 0.0, 0, 0.0, 0, 3, 1);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("カリン", "こちらでは、ＢＧＭの変更が\nできますよ\nどんな曲に変更しますか？\nふふふ、私も楽しみです♪", "2030/12/17 14:59:59", 1, 190801, -470.0, 19002, "2015/12/17 15:00:00", 19, 0.0, 0, 0.0, 0, 4, 1);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("カリン", "こちらでは、ＢＧＭを購入\nすることができますよ\n試聴することもできるので、\nじっくり選んでくださいね", "2030/12/17 14:59:59", 1, 190801, -470.0, 20001, "2015/12/17 15:00:00", 20, 0.0, 0, 0.0, 0, 5, 1);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("カリン", "いらっしゃいませ！\nＢＧＭの購入はこちらです\n素敵な曲がたくさんあって、\n目移りしちゃいますね", "2030/12/17 14:59:59", 1, 190801, -470.0, 20002, "2015/12/17 15:00:00", 20, 0.0, 0, 0.0, 0, 6, 1);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("キャル", "ここで手に入れたアイテムで\n専用装備を作成できるみたいね\nアイテムが集まったら\nさっそく作ってみましょ！", "2030/12/17 14:59:59", 1, 106001, -363.0, 21001, "2015/12/17 15:00:00", 21, 0.0, 0, 0.0, 0, 1, 1);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("コッコロ", "攻略すると珍しいアイテムが\n手に入りますよ\nこのアイテムで専用装備を\n作成できるようです", "2030/12/17 14:59:59", 1, 105901, -363.0, 21002, "2015/12/17 15:00:00", 21, 0.0, 0, 0.0, 0, 1, 1);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("シェフィ", "専用装備が欲しいなら\nこのクエストに挑戦するといいわ\n集めた素材でもっともっと\n強くなりましょう", "2030/12/17 14:59:59", 2, 106401, -363.0, 21003, "2015/12/17 15:00:00", 21, 0.0, 2104010, 0.0, 0, 1, 1);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("ペコリーヌ", "専用装備の作成に必要な\nアイテムを獲得できますよ\nたくさん集めてどんどん\n強くなりましょう！", "2030/12/17 14:59:59", 1, 105801, -363.0, 21004, "2015/12/17 15:00:00", 21, 0.0, 0, 0.0, 0, 1, 1);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("カリン", "投票はこちらです\nあなたが応援したい女の子に\n思いを込めた一票を\nお願いします！", "2030/12/17 14:59:59", 1, 190801, -430.0, 22001, "2015/12/17 15:00:00", 22, 0.0, 0, 0.0, 0, 1, 1);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("カリン", "ようこそ！\nあなたが思いを寄せるのは\nどの女の子ですか？\n応援してあげてくださいね！", "2030/12/17 14:59:59", 1, 190801, -430.0, 22002, "2015/12/17 15:00:00", 22, 0.0, 0, 0.0, 0, 2, 1);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("カリン", "たくさんの投票、\nありがとうございました\n結果発表を楽しみに\n待っていてくださいね！", "2030/12/17 14:59:59", 1, 190801, -430.0, 23001, "2015/12/17 15:00:00", 23, 0.0, 0, 0.0, 0, 3, 1);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("カリン", "ただ今、人気投票の\n集計中です\n結果が出るまでもう少しだけ\nお待ちくださいね", "2030/12/17 14:59:59", 1, 190801, -430.0, 23002, "2015/12/17 15:00:00", 23, 0.0, 0, 0.0, 0, 4, 1);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("エリコ（バレンタイン）", "あなた様が手伝ってくださった\nチョコレートケーキ\n美味しくないはずがありませんわ", "2030/12/17 14:59:59", 1, 109001, -385.0, 24001, "2019/01/31 12:00:00", 24, 8.0, 0, 4.08, 10011, 1, 2);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("エリコ（バレンタイン）", "このような失敗、あなた様が\nするはずありません\nもう一度挑戦してみましょう", "2030/12/17 14:59:59", 1, 109001, -385.0, 24002, "2019/01/31 12:00:00", 24, 8.0, 0, 5.0, 10011, 2, 2);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("エリコ（バレンタイン）", "あなた様のために\n作っているケーキを\nあなた様に手伝っていただく……\nことになるなんて……クスクス", "2030/12/17 14:59:59", 1, 109001, -385.0, 24003, "2019/01/31 12:00:00", 24, 8.0, 0, 10.11, 10011, 3, 2);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("エリコ（バレンタイン）", "あまり気に病む必要はありませんわ\nこれからは私がたっぷりと\n時間をかけて教えて差し上げますから", "2030/12/17 14:59:59", 1, 109001, -385.0, 24004, "2019/01/31 12:00:00", 24, 8.0, 0, 4.0, 10011, 4, 2);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("エリコ（バレンタイン）", "今回は調子が悪かった……のですか？\nあなた様が手伝ってくれたものなら\nわたしはどんなものでも……クスクス", "2030/12/17 14:59:59", 1, 109001, -385.0, 24005, "2019/01/31 12:00:00", 24, 8.0, 0, 6.0, 10011, 5, 2);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("エリコ（バレンタイン）", "あなた様が手がけた\nチョコレートケーキは\n私にとっての宝物……\n侮辱する者は生かしておきませんわ", "2030/12/17 14:59:59", 1, 109002, 0.0, 24006, "2019/01/31 12:00:00", 24, 0.0, 0, 0.0, 10011, 6, 1);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("エリコ（バレンタイン）", "とても素晴らしい出来栄えですわ！\nあなた様にふさわしい\nチョコレートケーキができました", "2030/12/17 14:59:59", 1, 109002, 0.0, 24007, "2019/01/31 12:00:00", 24, 0.0, 0, 0.0, 10011, 7, 1);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("エリコ（バレンタイン）", "私を手伝ってくれたあなた様は\nすでに私の虜……\n甘い世界に誘って差し上げますわ", "2030/12/17 14:59:59", 1, 109002, 0.0, 24008, "2019/01/31 12:00:00", 24, 0.0, 0, 0.0, 10011, 8, 1);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("エリコ（バレンタイン）", "あなた様の愛情\nしかと受け止めました\nこれが……私たちの初めての\n共同作業ですわね……クスクス", "2030/12/17 14:59:59", 1, 109002, 0.0, 24009, "2019/01/31 12:00:00", 24, 0.0, 0, 0.0, 10011, 9, 1);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("エリコ（バレンタイン）", "これは世界一の\nチョコレートケーキですわ\nだって、あなた様が腕によりをかけて\n作ってくださったんですもの", "2030/12/17 14:59:59", 1, 109002, 0.0, 24010, "2019/01/31 12:00:00", 24, 0.0, 0, 0.0, 10011, 10, 1);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("シズル（バレンタイン）", "上手にできなくて残念だった？\nでも、弟くんの気持ちが嬉しいな\nいつだってお姉ちゃんは\nそばにいるからね♪", "2030/12/17 14:59:59", 1, 109101, -385.0, 24011, "2019/01/31 12:00:00", 24, 8.0, 0, 2.12, 10011, 1, 2);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("シズル（バレンタイン）", "うーん、弟くんには珍しく\n緊張しちゃったのかな？\nもう一度チャレンジしてみる？", "2030/12/17 14:59:59", 5, 109101, -385.0, 24012, "2019/01/31 12:00:00", 24, 8.0, 0, 4.19, 10011, 2, 2);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("シズル（バレンタイン）", "お姉ちゃんのお手伝い、\nよくできました！\nあー、\nまだつまみ食いしちゃダメだぞ！", "2030/12/17 14:59:59", 2, 109101, -385.0, 24013, "2019/01/31 12:00:00", 24, 8.0, 0, 2.3, 10011, 3, 4);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("シズル（バレンタイン）", "見てみて！\nスポンジに綺麗な焼き目がついてるよ\nさっすが弟くんだね！", "2030/12/17 14:59:59", 1, 109102, 0.0, 24014, "2019/01/31 12:00:00", 24, 0.0, 0, 0.0, 10011, 4, 1);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("シズル（バレンタイン）", "まぁまぁ、落ち込まないで\n見た目は……個性的だけど、\n味は絶対美味しいはずだから！", "2030/12/17 14:59:59", 5, 109101, -385.0, 24015, "2019/01/31 12:00:00", 24, 8.0, 0, 5.23, 10011, 5, 2);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("シズル（バレンタイン）", "弟くんみたいな\n可愛いケーキができたよ！\n早く食べてみたいでしょ♪", "2030/12/17 14:59:59", 1, 109102, 0.0, 24016, "2019/01/31 12:00:00", 24, 0.0, 0, 0.0, 10011, 6, 1);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("シズル（バレンタイン）", "あれれ？　弟くん、指に\nチョコレートがくっついてるよ？\nお姉ちゃんが舐めてあげるね、\nはぁむ！", "2030/12/17 14:59:59", 1, 109101, -385.0, 24017, "2019/01/31 12:00:00", 24, 8.0, 0, 5.01, 10011, 7, 2);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("シズル（バレンタイン）", "なかなか上手にできたんじゃない？\nでも弟くんはまだまだできる子！\nお姉ちゃん、信じてるからね", "2030/12/17 14:59:59", 1, 109102, 0.0, 24018, "2019/01/31 12:00:00", 24, 0.0, 0, 0.0, 10011, 8, 1);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("シズル（バレンタイン）", "わぁ～、\nとっても美味しそうにできたね！\n弟くん手慣れてたから\nお姉ちゃん安心して任せられちゃった！", "2030/12/17 14:59:59", 1, 109102, 0.0, 24019, "2019/01/31 12:00:00", 24, 0.0, 0, 0.0, 10011, 9, 1);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("シズル（バレンタイン）", "や～ん、弟くんが手伝ってくれた\nチョコレートケーキ！\nすっごく美味しそうにできたね♪", "2030/12/17 14:59:59", 1, 109102, 0.0, 24020, "2019/01/31 12:00:00", 24, 0.0, 0, 0.0, 10011, 10, 1);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("シェフィ", "ここから先は神聖な場所みたい\nどんなお宝が眠っているのか、\n今から探索するのが楽しみね♪", "2030/12/17 14:59:59", 2, 106401, -363.0, 26001, "2015/12/17 15:00:00", 26, 0.0, 2104010, 0.0, 0, 1, 1);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("ペコリーヌ", "ここから先は神聖な場所\nみたいです！\nどんなお宝が手に入るか\n楽しみですね！", "2030/12/17 14:59:59", 1, 105801, -363.0, 26002, "2015/12/17 15:00:00", 26, 0.0, 0, 0.0, 0, 1, 1);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("キャル", "この先は神聖な場所みたい。\n手に入るお宝も並じゃないけど\n気を付けていかないと\n痛い目にあうわよ", "2030/12/17 14:59:59", 1, 106001, -363.0, 26003, "2015/12/17 15:00:00", 26, 0.0, 0, 0.0, 0, 1, 1);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("コッコロ", "ここから先は神聖な場所\nでございます。\n気を引き締めてお宝の\n調査探索に参りましょう", "2030/12/17 14:59:59", 1, 105901, -363.0, 26004, "2015/12/17 15:00:00", 26, 0.0, 0, 0.0, 0, 1, 1);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("シェフィ", "ここにさらなる力を得るための\nアイテムが眠っている…って\nみんな言ってるわ。ふふっ、\nそれじゃあ挑戦してみましょうか", "2030/12/17 14:59:59", 2, 106401, -363.0, 27001, "2015/12/17 15:00:00", 27, 0.0, 2104010, 0.0, 0, 1, 1);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("ペコリーヌ", "ここにさらなる力を得るための\nアイテムが眠っているみたい\nです！　どこから挑戦するか\n迷っちゃいますね！", "2030/12/17 14:59:59", 1, 105801, -363.0, 27002, "2015/12/17 15:00:00", 27, 0.0, 0, 0.0, 0, 1, 1);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("キャル", "ここにさらなる力を得るための\nアイテムが眠っているみたい！\nどんどん挑戦して\n強くなっちゃいましょ！", "2030/12/17 14:59:59", 1, 106001, -363.0, 27003, "2015/12/17 15:00:00", 27, 0.0, 0, 0.0, 0, 1, 1);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("コッコロ", "こちらにさらなる力を得る\nためのアイテムが眠っている\nようです。主さま、どこから\n挑戦いたしましょう。", "2030/12/17 14:59:59", 1, 105901, -363.0, 27004, "2015/12/17 15:00:00", 27, 0.0, 0, 0.0, 0, 1, 1);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("カリン", "ようこそ！\n皆さんの素敵な出会いを\nギルド管理協会が\nお手伝いします！", "2030/12/17 14:59:59", 1, 190801, -363.0, 28001, "2019/09/24 15:00:00", 28, 0.0, 0, 0.0, 0, 1, 1);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("カリン", "ギルド管理協会です\nフレンドに関しては\nこちらでご確認ください", "2030/12/17 14:59:59", 1, 190801, -363.0, 28002, "2019/09/24 15:00:00", 28, 0.0, 0, 0.0, 0, 2, 1);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("カリン", "こちらがフレンドの\n皆さんです\n素敵な関係を\n築いてくださいね！", "2030/12/17 14:59:59", 1, 190801, -409.0, 29001, "2019/09/24 15:00:00", 29, 0.0, 0, 0.0, 0, 3, 1);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("カリン", "こちらの一覧で\nフレンドのプロフィールを\n確認できますよ", "2030/12/17 14:59:59", 1, 190801, -409.0, 29002, "2019/09/24 15:00:00", 29, 0.0, 0, 0.0, 0, 4, 1);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("カリン", "フレンド管理は\nこちらになります\n新しいフレンドとの出会いを\n楽しんでくださいね！", "2030/12/17 14:59:59", 1, 190801, -409.0, 30001, "2019/09/24 15:00:00", 30, 0.0, 0, 0.0, 0, 5, 1);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("カリン", "フレンドの申請や\n承認ができますよ\nどうぞ、良き交流を！", "2030/12/17 14:59:59", 1, 190801, -409.0, 30002, "2019/09/24 15:00:00", 30, 0.0, 0, 0.0, 0, 6, 1);
