INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("カリン", "気になるパーティと\nバトルをしてみましょう！\nどちらが勝利するのか、\n私も楽しみにしていますね", "2030/12/17 14:59:59", 1, 190801, -409.0, 31002, "2019/10/31 12:00:00", 31, 0.0, 0, 0.0, 0, 8, 1);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("カリン", "ルーキーの皆さんのために\n特別なミッションを\nご用意いたしました！\nぜひ、挑戦してください！", "2020/01/04 4:59:59", 1, 190801, -409.0, 32001, "2019/12/20 5:00:00", 32, 0.0, 0, 0.0, 0, 1, 1);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("カリン", "期間限定のキャンペーンを\n開催中です！\nミッションにチャレンジ\nしましょう！", "2020/01/04 4:59:59", 1, 190801, -409.0, 32002, "2019/12/20 5:00:00", 32, 0.0, 0, 0.0, 0, 2, 1);
