INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("カリン", "期間限定のキャンペーンを\n開催中です！\nミッションにチャレンジ\nしましょう！", "2020/01/04 4:59:59", 1, 190801, -409.0, 33002, "2019/12/20 5:00:00", 33, 0.0, 0, 0.0, 0, 4, 1);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("カリン", "お疲れ様でした！\nミッションの報酬の受け取りは\nこちらからできますよ！", "2020/01/10 11:59:59", 1, 190801, -409.0, 34001, "2020/01/04 5:00:00", 34, 0.0, 0, 0.0, 0, 5, 1);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("カリン", "ミッション報酬の受け取りは\nこちら！\n受け取り漏れの無いように\n気を付けてくださいね！", "2020/01/10 11:59:59", 1, 190801, -409.0, 34002, "2020/01/04 5:00:00", 34, 0.0, 0, 0.0, 0, 6, 1);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("ペコリーヌ", "過去のストーリーイベントを\n楽しめちゃいますよ！\n遊んだことのないものがあれば\n一緒にやってみましょう♪", "2030/12/17 14:59:59", 1, 105801, -458.0, 38001, "2015/12/17 15:00:00", 38, 0.0, 0, 5.3, 0, 1, 2);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("ペコリーヌ", "これまでのイベントで登場した\n限定キャラを仲間にできたり\nメモリーピースが手に入る\nみたいですよ。やばいですね☆", "2030/12/17 14:59:59", 1, 105801, -458.0, 38002, "2015/12/17 15:00:00", 38, 0.0, 0, 6.5, 0, 2, 2);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("ペコリーヌ", "", "2020/04/08 23:59:59", 3, 105801, 9999.0, 39005, "2020/04/01", 39, 9999.0, 0, 0.0, 0, 0, 3);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("カリン", "これまでに出題された\n問題を振り返ることが\nできますよ\n復習は大切です♪", "2030/12/17 14:59:59", 1, 190801, -430.0, 40001, "2015/12/17 15:00:00", 40, 0.0, 0, 0.0, 0, 2, 1);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("シェフィ", "ここでは腕試しが\nできるんですって。\n自分の実力を測るのに、\nちょうどよさそうね。", "2030/12/17 14:59:59", 1, 106401, -363.0, 41001, "2015/12/17 15:00:00", 41, 0.0, 2104010, 0.0, 0, 1, 1);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("ペコリーヌ", "ここで腕試しを\nしていきましょう！\n全力全開、\nがんばっちゃいますよ～！", "2030/12/17 14:59:59", 1, 105801, -363.0, 41002, "2015/12/17 15:00:00", 41, 0.0, 0, 0.0, 0, 1, 1);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("キャル", "ここで腕試しが\nできるみたいね。\n試してみるのも\nいいんじゃない？", "2030/12/17 14:59:59", 1, 106001, -363.0, 41003, "2015/12/17 15:00:00", 41, 0.0, 0, 0.0, 0, 1, 1);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("コッコロ", "腕試しができるようです。\nここで練習を重ね、実戦に\n活かしてまいりましょう。", "2030/12/17 14:59:59", 1, 105901, -363.0, 41004, "2015/12/17 15:00:00", 41, 0.0, 0, 0.0, 0, 1, 1);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("コッコロ", "訓練の成果に応じて、\n報酬がもらえるそうです。\n共に励んでいきましょう。", "2030/12/17 14:59:59", 1, 105901, -416.5, 42001, "2015/12/17 15:00:00", 42, 0.0, 0, 0.0, 0, 1, 1);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("シェフィ", "目標を達成すれば、\n報酬がもらえるみたい。\n頑張り甲斐があるわね。", "2030/12/17 14:59:59", 1, 106401, -416.5, 42002, "2015/12/17 15:00:00", 42, 0.0, 2104010, 0.0, 0, 1, 1);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("ペコリーヌ", "腕試しをがんばれば、\n報酬がもらえますよ。\n挑戦していきましょう☆", "2030/12/17 14:59:59", 1, 105801, -416.5, 42003, "2015/12/17 15:00:00", 42, 0.0, 0, 0.0, 0, 1, 1);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("キャル", "ミッションを達成すると、\n報酬が出るんですって。\n一緒にやってみましょ！", "2030/12/17 14:59:59", 1, 106001, -416.5, 42004, "2015/12/17 15:00:00", 42, 0.0, 0, 0.0, 0, 1, 1);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("ペコリーヌ", "ここからアリーナに\n挑戦できますよ！\n編成を工夫してライバルに\n挑んじゃいましょう！", "2030/12/17 14:59:59", 1, 105801, -363.0, 43001, "2015/12/17 15:00:00", 43, 0.0, 0, 0.0, 0, 1, 1);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("コッコロ", "こちらからアリーナに\n挑戦することができます。\n主さまらしい編成で\nライバルに挑みましょう。", "2030/12/17 14:59:59", 1, 105901, -363.0, 43002, "2015/12/17 15:00:00", 43, 0.0, 0, 0.0, 0, 1, 1);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("キャル", "ここからアリーナに\n挑戦できるわよ！\nしっかり編成を考えて\nライバルに挑みなさい！", "2030/12/17 14:59:59", 1, 106001, -363.0, 43003, "2015/12/17 15:00:00", 43, 0.0, 0, 0.0, 0, 1, 1);
INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("アメス", "ミッションをクリアすると報酬が\n受け取れるわ。ジャンジャン\nクリアしてバリバリ強化して\nあげなさい♪", "2030/12/17 14:59:59", 1, 123001, -416.5, 43004, "2015/12/17 15:00:00", 44, 0.0, 0, 0.0, 0, 1, 1);
