INSERT INTO `v1_814050072913c61375329e1209c50b51f927257b39496b97a23cd04db3e64ac7` VALUES ("アメス", "ちょっとあんた、報酬が\n受け取れるじゃない！\n忘れずにチェックなさい。\nアメス様との約束よ？", "2030/12/17 14:59:59", 1, 123001, -416.5, 43006, "2015/12/17 15:00:00", 45, 0.0, 0, 5.79, 0, 3, 2);
